#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e6+5,MOD=1e5+3;
vector<int> g[MAXN];
int d[MAXN],cnt[MAXN],n,m;
bool vis[MAXN];
signed main(void)
{
    n=read(),m=read();
    FOR(i,1,m)
	{
        int x=read(),y=read();
        g[x].pb(y);
		g[y].pb(x);
    }
    queue<int>q;
    d[1]=0;
    vis[1]=true;
	q.push(1);
	cnt[1]=1;
    wh(q.size())
	{
        int x=q.front();
        q.pop();
        FOI(t,g[x])
		{
            if(!vis[t])
			{
				vis[t]=true;
				d[t]=d[x]+1;
				q.push(t);
			}
            if(d[t]==d[x]+1)
			{
				cnt[t]=(cnt[t]+cnt[x])%MOD;
			}
        }
    }
    FOR(i,1,n)
	{
		writeln(cnt[i]);	
	}
    return false;
}
